import{_ as e,o as a,c as o,a2 as l}from"./chunks/framework.BQ1gajhD.js";const g=JSON.parse('{"title":"牌楼院与昭泰门","description":"","frontmatter":{},"headers":[],"relativePath":"religion/yonghegong/pailou-yuan.md","filePath":"religion/yonghegong/pailou-yuan.md","lastUpdated":1784720050000}'),i={name:"religion/yonghegong/pailou-yuan.md"};function r(n,t,u,d,s,h){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="牌楼院与昭泰门" tabindex="-1">牌楼院与昭泰门 <a class="header-anchor" href="#牌楼院与昭泰门" aria-label="Permalink to &quot;牌楼院与昭泰门&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1763912111352-fc738735c31c?w=1200&amp;q=80" alt="牌楼院与昭泰门"></p><blockquote><p>&quot;三座牌楼拱卫，一道影壁当门——未入山门，先见皇家气象。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>牌楼院是雍和宫中轴线最南端的第一进院落，也是由尘世步入梵境的前奏。院落东西北三面各矗立一座三间四柱牌楼，南端横亘砖雕大影壁，围合出一方庄严肃穆的引导空间。穿过院落北端的昭泰门，便正式进入雍和宫的正殿区。</p><p>这一带是雍和宫王府时期最直接的遗存。康熙三十三年（1694年），此处始建为皇四子胤禛的府邸；康熙四十八年胤禛晋封雍亲王，门庭按亲王府规制营建。乾隆九年（1744年）雍和宫改为喇嘛庙后，牌楼院与昭泰门不仅被完整保留，更经乾隆帝御题匾额、增饰修缮，成为&quot;入寺升殿&quot;礼仪序列的起点——三座牌楼与影壁昭示着此地的尊贵身份，也提醒来者整肃身心。</p><p>牌楼院的空间秩序意味深长：南以影壁界隔屏蔽，东西牌楼左右导引，北牌楼当轴而立。来者先由四面八方汇聚于此，再循唯一轴线向北，自然完成&quot;纳四方、归一心&quot;的空间仪式。自影壁至昭泰门，地势微微抬升，脚步渐缓，心绪渐敛——这便是皇家寺院前导空间的营造匠心。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">位置</th><th style="text-align:left;">规制与特色</th></tr></thead><tbody><tr><td style="text-align:left;">北牌楼</td><td style="text-align:left;">牌楼院北端</td><td style="text-align:left;">三间四柱，黄琉璃瓦顶，乾隆御题&quot;寰海尊亲&quot;（南面）、&quot;群生仁寿&quot;（北面）</td></tr><tr><td style="text-align:left;">东牌楼</td><td style="text-align:left;">牌楼院东侧</td><td style="text-align:left;">乾隆御题&quot;慈福崇仁&quot;、&quot;十方正觉&quot;</td></tr><tr><td style="text-align:left;">西牌楼</td><td style="text-align:left;">牌楼院西侧</td><td style="text-align:left;">乾隆御题&quot;福仁布胜&quot;、&quot;界绰恒通&quot;</td></tr><tr><td style="text-align:left;">砖雕影壁</td><td style="text-align:left;">牌楼院南端</td><td style="text-align:left;">青砖精雕，图案繁丽，界定圣地、屏蔽尘嚣</td></tr><tr><td style="text-align:left;">昭泰门</td><td style="text-align:left;">牌楼院北端</td><td style="text-align:left;">三门并立，原王府正门遗构，连接牌楼院与正殿区</td></tr></tbody></table><p>三座牌楼匾额寓意深远：&quot;寰海尊亲&quot;意为天下苍生如敬父母般尊崇至亲，&quot;群生仁寿&quot;祝愿众生同享仁德寿考，&quot;十方正觉&quot;则指向佛法普照十方、觉悟有情。匾额辞气恢宏，既是颂圣，也是弘法。</p><p>昭泰门面阔三间，取&quot;昭示安泰&quot;之意。作为亲王府时代的大门遗构，它保留了王府规制的开间尺度，改寺后成为外山门，门前古槐参天，门内甬道笔直，直抵雍和门。</p><h3 id="影壁与牌楼的礼制功能" tabindex="-1">影壁与牌楼的礼制功能 <a class="header-anchor" href="#影壁与牌楼的礼制功能" aria-label="Permalink to &quot;影壁与牌楼的礼制功能&quot;">​</a></h3><p>影壁是中国传统宅邸与寺院的&quot;第一道屏障&quot;：对外屏蔽视线与尘嚣，对内界定神圣空间的起点。雍和宫的砖雕大影壁横亘院落最南端，使寺内景象不致一览无余，来客须绕行而入，敬意由此而生。三座牌楼则是礼制等级的标志——按清制，牌楼本为旌表功德、标示尊卑而设，雍和宫一院三牌楼且皆出御题，规格之高，在京师寺院中绝无仅有。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="从王府门庭到寺院前导" tabindex="-1">从王府门庭到寺院前导 <a class="header-anchor" href="#从王府门庭到寺院前导" aria-label="Permalink to &quot;从王府门庭到寺院前导&quot;">​</a></h3><p>雍亲王府时期的正门规制，按《大清会典》亲王府&quot;正门三间&quot;之制建造。1744年改为喇嘛庙时，乾隆帝并未拆旧建新，而是沿用王府门庭并增建牌楼、御题匾额，使王府的尊贵与寺院的庄严合为一体。这种&quot;因府为寺&quot;的格局，在北京寺院中独一无二，也是雍和宫区别于一般寺庙的根本所在。</p><h3 id="牌楼匾额皆出御笔" tabindex="-1">牌楼匾额皆出御笔 <a class="header-anchor" href="#牌楼匾额皆出御笔" aria-label="Permalink to &quot;牌楼匾额皆出御笔&quot;">​</a></h3><p>雍和宫三座牌楼的六面匾额，相传均为乾隆帝御笔亲题，汉文之外旧日另附满文。帝王为一座寺院的前导院落一一题额，在清代并不多见，足见雍和宫在清廷心目中的特殊地位——它既是皇家寺院，更是联络蒙藏、怀柔四方的政治象征。</p><h3 id="从-四爷府-到十方丛林" tabindex="-1">从&quot;四爷府&quot;到十方丛林 <a class="header-anchor" href="#从-四爷府-到十方丛林" aria-label="Permalink to &quot;从&quot;四爷府&quot;到十方丛林&quot;">​</a></h3><p>1744年的改寺，并非简单的功能转换。乾隆帝在章嘉呼图克图等蒙藏高僧的建议下，将行宫正式改为藏传佛教寺院，任命蒙古高僧为住持，设立扎仓（学院），派驻学僧，使之成为内地格鲁派的中心丛林。牌楼院作为王府的&quot;门面&quot;被完整保留——新来的蒙藏僧侣穿过御题牌楼、进入昭泰门的那一刻，便直观地感受到清廷对藏传佛教的尊崇：这不是偏居一隅的边地经院，而是天子脚下的国家道场。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>三座御题牌楼</strong>：东、西、北三座牌楼与匾额构成完整的礼仪前导，为北京寺院孤例。</li><li><strong>砖雕大影壁</strong>：南端影壁青砖精雕，是界定圣地空间的重要标志。</li><li><strong>王府规制遗存</strong>：昭泰门三门并立的开间尺度，清晰保留了亲王府正门的规制。</li><li><strong>匾额辞章</strong>：&quot;寰海尊亲&quot;&quot;群生仁寿&quot;&quot;十方正觉&quot;等御题匾额，辞气恢宏，值得逐一辨读。</li><li><strong>中轴线起点</strong>：由此北望，六进殿宇沿中轴层层抬高，寺院格局一览在目。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>建议在此稍作停留，先读牌楼匾额、再入寺院，方能体会&quot;由府而宫、由宫而寺&quot;的历史脉络。</li><li>牌楼匾额位置较高，可借助长焦或手机变焦细读御题文字。</li><li>拍摄三座牌楼，以昭泰门或影壁为前景，最能体现院落纵深感。</li><li>昭泰门内即检票区域，请提前备好门票。</li><li>院外雍和宫大街一侧亦有不少祈福香烛店铺，寺内提供免费香，无需购买外香。</li></ul><hr><p><strong>📍 位置</strong>：雍和宫中轴线最南端，第一进院落 <strong>⏱️ 建议游览</strong>：15-20分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/religion/yonghegong/">雍和宫概览</a></p><p><strong>➡️ 下一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/yonghe-men.html">雍和门（天王殿）</a></p>',27)])])}const p=e(i,[["render",r]]);export{g as __pageData,p as default};
